import 'package:flutter/material.dart'; import 'package:dhv_lingoo/config/theme.dart'; import 'package:go_router/go_router.dart'; class SplashScreen extends StatefulWidget { const SplashScreen({super.key}); @override State<SplashScreen> createState() => _SplashScreenState(); } class _SplashScreenState extends State<SplashScreen> { @override void initState() { super.initState(); Future.delayed(const Duration(seconds: 2), () { if (mounted) context.go('/login'); }); } @override Widget build(BuildContext context) => Scaffold(backgroundColor: AppTheme.primary, body: const Center(child: Text('DHV-Lingoo', style: TextStyle(fontSize: 32, fontWeight: FontWeight.w900, color: Colors.white)))); }
